set-variable.value:
#[%dw 2.0
output application/java

var data = if (payload is Array) payload[0] else payload

fun getVal(v) =
    if (v is Array) v[0]
    else v default ""

---
"<!DOCTYPE html>

<html>

<head>

<meta charset='UTF-8'>

<style>

body{
    margin:0;
    padding:40px 0;
    background:#f4f7fb;
    font-family:Arial,Helvetica,sans-serif;
}

.container{
    width:680px;
    margin:auto;
    background:#ffffff;
    border-radius:15px;
    overflow:hidden;
    box-shadow:0 10px 35px rgba(0,0,0,.15);
}

.header{
    background:linear-gradient(90deg,#8B0000,#d32f2f);
    color:white;
    text-align:center;
    padding:35px;
}

.logo{
    font-size:32px;
    font-weight:bold;
}

.tagline{
    margin-top:8px;
    font-size:14px;
    opacity:.9;
}

.banner{
    text-align:center;
    padding:35px;
}

.icon{
    width:90px;
    height:90px;
    line-height:90px;
    margin:auto;
    border-radius:50%;
    background:#dc2626;
    color:white;
    font-size:42px;
}

.banner h2{
    color:#b91c1c;
    margin-top:20px;
}

.banner p{
    color:#555;
}

.card{
    margin:30px;
    border:1px solid #e5e7eb;
    border-radius:10px;
    overflow:hidden;
}

.card-title{
    background:#f8fafc;
    padding:18px;
    font-size:20px;
    font-weight:bold;
    color:#8B0000;
}

table{
    width:100%;
    border-collapse:collapse;
}

td{
    padding:16px;
    border-bottom:1px solid #eeeeee;
}

.label{
    font-weight:bold;
    color:#555;
}

.value{
    text-align:right;
    color:#111827;
}

.status{
    color:#dc2626;
    font-weight:bold;
    font-size:18px;
}

.notice{
    margin:30px;
    background:#fff4f4;
    border-left:6px solid #dc2626;
    padding:20px;
    border-radius:6px;
    color:#555;
}

.footer{
    background:#f8fafc;
    text-align:center;
    padding:30px;
    font-size:13px;
    color:#666;
}

.footer b{
    color:#003366;
}

</style>

</head>

<body>

<div class='container'>

<div class='header'>

<div class='logo'>
🏦 " ++ (payload.BANKNAME[0] default "N/A") ++ "
</div>

<div class='tagline'>
Secure • Trusted • Digital Banking
</div>

</div>

<div class='banner'>

<div class='icon'>
🔒
</div>

<h2>Account Successfully Deactivated</h2>

<p>

Dear <b>"
++
upper(getVal(vars.FULLNAME))
++
"</b>,

<br/><br/>

Your account has been successfully deactivated as requested.

</p>

</div>

<div class='card'>

<div class='card-title'>

Account Information

</div>

<table>

<tr>

<td class='label'>Customer Name</td>

<td class='value'>"
++
upper(getVal(vars.FULLNAME))
++
"</td>

</tr>

<tr>

<td class='label'>Bank Name</td>

<td class='value'>"
++
getVal(data.BANKNAME)
++
"</td>

</tr>

<tr>

<td class='label'>Account Number</td>

<td class='value'>"
++
getVal(data.ACCOUNTNUMBER)
++
"</td>

</tr>

<tr>

<td class='label'>Account Status</td>

<td class='value status'>
DEACTIVATED
</td>

</tr>

<tr>

<td class='label'>Effective Date</td>

<td class='value'>
"
++
(now() as String {format:"dd MMM yyyy hh:mm:ss a"})
++
"
</td>

</tr>

</table>

</div>

<div class='notice'>

<b>⚠ Security Notice</b>

<br/><br/>

If you did not request this account deactivation, please contact our
24×7 Customer Support immediately to secure your account.

</div>

<div class='footer'>

<b>Real Bank</b>

<br/><br/>

📞 Customer Care : +91 9494207062

<br/>

✉ support@realbank.com

<br/>

🌐 www.realbank.com

<br/><br/>

© 2026 Real Bank. All Rights Reserved.

<br/><br/>

This is a system-generated email. Please do not reply.

</div>

</div>

</body>

</html>"]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
	bank_account_detailes: {
		"account_data": {
			"message": "The account has been deactivated successfully, and an email has been sent to the user.",
			"accountNumber": vars.accountNumber
		}
	}
}

set-variable.value:
#[%dw 2.0
output application/java

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>

<style>
body {
    margin: 0;
    padding: 40px 0;
    background: #f4f7fb;
    font-family: Arial, Helvetica, sans-serif;
}

.container {
    width: 680px;
    margin: auto;
    background: #ffffff;
    border-radius: 16px;
    overflow: hidden;
    box-shadow: 0 12px 35px rgba(0, 0, 0, .12);
}

.header {
    background: linear-gradient(90deg, #0047AB, #0066CC);
    color: white;
    text-align: center;
    padding: 35px;
}

.logo {
    font-size: 32px;
    font-weight: bold;
}

.tagline {
    margin-top: 8px;
    font-size: 14px;
    opacity: .9;
}

.success {
    text-align: center;
    padding: 35px 30px;
}

.icon {
    width: 90px;
    height: 90px;
    line-height: 90px;
    margin: auto;
    border-radius: 50%;
    background: #16a34a;
    color: white;
    font-size: 42px;
}

.success h2 {
    color: #16a34a;
    margin-top: 20px;
    margin-bottom: 10px;
}

.success p {
    color: #555;
    line-height: 1.6;
}

.card {
    margin: 30px;
    border: 1px solid #e5e7eb;
    border-radius: 12px;
    overflow: hidden;
}

.card-title {
    background: #f8fafc;
    color: #003366;
    font-size: 20px;
    font-weight: bold;
    padding: 18px;
}

table {
    width: 100%;
    border-collapse: collapse;
}

td {
    padding: 16px;
    border-bottom: 1px solid #ececec;
}

.label {
    width: 40%;
    font-weight: bold;
    color: #555;
}

.value {
    color: #111827;
}

.status {
    color: #16a34a;
    font-weight: bold;
}

.notice {
    margin: 30px;
    background: #eef7ff;
    border-left: 6px solid #2196F3;
    padding: 20px;
    border-radius: 8px;
    color: #444;
}

.footer {
    background: #f8fafc;
    text-align: center;
    padding: 30px;
    font-size: 13px;
    color: #666;
}

.footer b {
    color: #003366;
}
</style>

</head>

<body>

<div class='container'>

<div class='header'>
    <div class='bank'>
        🏦 " ++ (payload.BANKNAME[0] default "N/A") ++ "
    </div>
    <div class='tagline'>
        Safe • Secure • Digital Banking
    </div>
</div>

<div class='success'>
    <div class='icon'>✓</div>
    <h2>Account Updated Successfully</h2>
    <p>
        Dear <b>" ++ (vars.inputPayload.FullName default "Customer") ++ "</b>,
        <br/><br/>
        Your account information has been successfully updated in our banking system.
    </p>
</div>

<div class='card'>
    <div class='card-title'>Updated Account Details</div>
    <table>
        <tr>
            <td class='label'>Reference Number</td>
            <td class='value'>" ++ (vars.transactionId default "RBK-" ++ (now() as String {format: "yyyyMMddHHmmss"})) ++ "</td>
        </tr>
        <tr>
            <td class='label'>Account Number</td>
            <td class='value'>" ++ (vars.accountNumber default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Customer Name</td>
            <td class='value'>" ++ (vars.inputPayload.FullName default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Mobile Number</td>
            <td class='value'>" ++ (vars.inputPayload.mobileNumber default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Email Address</td>
            <td class='value'>" ++ (vars.email default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Aadhaar</td>
            <td class='value'>XXXX XXXX " ++ ((vars.adharNumber as String default "XXXX XXXX")[-4 to -1]) ++ "</td>
        </tr>
        <tr>
            <td class='label'>Address</td>
            <td class='value'>" ++ (vars.inputpayload.address default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Bank Name</td>
            <td class='value'>" ++ (vars.BANKNAME default "N/A") ++ "</td>
        </tr>
        <tr>
            <td class='label'>Updated On</td>
            <td class='value'>" ++ (now() as String {format: "dd MMM yyyy hh:mm:ss a"}) ++ "</td>
        </tr>
        <tr>
            <td class='label'>Status</td>
            <td class='value status'>SUCCESS</td>
        </tr>
    </table>
</div>

<div class='notice'>
    <b>🔒 Security Notice</b>
    <br/><br/>
    If you did not request this account update, please contact our 24×7 Customer Care immediately. Protect your banking credentials and never share your OTP, PIN, CVV, or passwords with anyone.
</div>

<div class='footer'>
    <b>Real Bank</b>
    <br/><br/>
    📞 Customer Care: +91 9494207062
    <br/>
    ✉ support@realbank.com
    <br/>
    🌐 www.realbank.com
    <br/><br/>
    © 2026 Real Bank. All Rights Reserved.
    <br/><br/>
    This is an automated notification. Please do not reply to this email.
</div>

</div>

</div>

</body>

</html>"]

ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
	bank_account_detailes: {
		"account_data": {
			"status": "Success",
			"statusCode": 200,
			"message": "The account has been updated successfully, and an email has been sent successfully.",
			"accountNumber": vars.accountNumber,
			"user_input_data": {
				"input_data": vars.inputpayload
			}
		}
	}
}

%dw 2.0
output application/json
---
{
	"bank_account_detailes": {
		"account_status": {
			"status": "FAILED",
			"statusCode": "404",
			"message": "An account does not exists with the provided customer details. Please try with new details. If you are a new customer, please validate your information."	
		}
	}
}

set-variable.value:
#[%dw 2.0
output application/java

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>

<style>
body {
    margin: 0;
    padding: 0;
    background: #edf2f7;
    font-family: 'Segoe UI', Arial, sans-serif;
}

.wrapper {
    width: 100%;
    padding: 30px 0;
}

.container {
    max-width: 760px;
    margin: auto;
    background: white;
    border-radius: 18px;
    overflow: hidden;
    box-shadow: 0 10px 40px rgba(0, 0, 0, .12);
}

.header {
    background: linear-gradient(135deg, #003366, #0056b3, #007bff);
    padding: 35px;
    color: white;
}

.bank {
    font-size: 34px;
    font-weight: bold;
}

.tag {
    margin-top: 5px;
    font-size: 15px;
    opacity: .9;
}

.hero {
    padding: 35px;
    background: #f8fbff;
}

.hero h2 {
    margin: 0;
    color: #003366;
}

.hero p {
    line-height: 28px;
    color: #666;
}

.card {
    margin: 30px;
    border-radius: 15px;
    overflow: hidden;
    border: 1px solid #dde5ee;
}

.card-title {
    background: #003366;
    padding: 18px;
    color: white;
    font-size: 18px;
    font-weight: bold;
}

table {
    width: 100%;
    border-collapse: collapse;
}

td {
    padding: 16px;
    border-bottom: 1px solid #ececec;
    font-size: 15px;
}

td:first-child {
    font-weight: bold;
    background: #fafafa;
    width: 40%;
}

.balance {
    font-size: 28px;
    font-weight: bold;
    color: #009933;
}

.status {
    background: #d9f7e8;
    color: #0b8a3b;
    padding: 6px 14px;
    border-radius: 30px;
    display: inline-block;
    font-weight: bold;
}

.info {
    display: flex;
    gap: 18px;
    padding: 0 25px 25px;
}

.box {
    flex: 1;
    background: #f7fbff;
    padding: 22px;
    border-radius: 15px;
    text-align: center;
    border: 1px solid #d7e8ff;
}

.box h3 {
    margin: 10px 0;
    color: #003366;
}

.box p {
    font-size: 13px;
    color: #666;
    line-height: 22px;
}

.security {
    margin: 25px;
    padding: 20px;
    background: #fff8ea;
    border-left: 5px solid orange;
    border-radius: 10px;
}

.security h3 {
    margin-top: 0;
    color: #c67d00;
}

.footer {
    background: #003366;
    color: white;
    text-align: center;
    padding: 35px;
    font-size: 13px;
    line-height: 24px;
}

.footer a {
    color: #fff;
    text-decoration: none;
}
</style>

</head>

<body>

<div class='wrapper'>

<div class='container'>

<div class='header'>

<div class='bank'>
🏦 " ++ (payload.BANKNAME[0] default "N/A") ++ "
</div>

<div class='tag'>
Secure • Trusted • Digital Banking
</div>

</div>

<div class='hero'>

<h2>
Welcome,
<b>" ++ (upper(vars.inputpayload.FULLNAME[0]) default "N/A") ++ "</b> 👋
</h2>

<p>
Congratulations!
Please find your account details below.
Thank you for choosing <b>Real Bank</b> as your trusted financial partner.
</p>

</div>

<div class='card'>

<div class='card-title'>
💳 Account Details
</div>

<table>

<tr>
<td>Account Holder</td>
<td>" ++ (payload.FULLNAME[0] default "N/A") ++ "</td>
</tr>

<tr>
<td>Bank Name</td>
<td>" ++ (vars.bankname default "N/A") ++ "</td>
</tr>

<tr>
<td>Account Number</td>
<td><b>" ++ (vars.inputpayload.ACCOUNTNUMBER[0] default "N/A") ++ "</b></td>
</tr>

<tr>
<td>Date of Birth</td>
<td>" ++ (vars.inputpayload.DATEOFBIRTH[0] default "N/A") ++ "</td>
</tr>

<tr>
<td>Mobile Number</td>
<td>" ++ (vars.inputpayload.MOBILENUMBER[0] default "N/A") ++ "</td>
</tr>

<tr>
<td>Email Address</td>
<td>" ++ (vars.email default "customer@email.com") ++ "</td>
</tr>

<tr>
<td>Aadhaar</td>
<td>XXXX XXXX " ++ ((vars.inputpayload.ADHARNUMBER[0] as String default "N/A")[-4 to -1]) ++ "</td>
</tr>

<tr>
<td>Address</td>
<td>" ++ (vars.inputpayload.ADDRESS[0] default "N/A") ++ "</td>
</tr>

<tr>
<td>Status</td>
<td><span class='status'>" ++ (vars.status default "N/A") ++ "</span></td>
</tr>

<tr>
<td>Available Balance</td>
<td class='balance'>₹ " ++ (vars.inputpayload.BALANCE[0] default "0.00") ++ "</td>
</tr>

</table>

</div>

<div class='security'>

<h3>
🔒 Banking Security
</h3>

<ul>
<li>Never share your ATM PIN.</li>
<li>Never share OTP with anyone.</li>
<li>Real Bank never asks for passwords.</li>
<li>Enable SMS & Email transaction alerts.</li>
<li>Report fraudulent transactions immediately.</li>
</ul>

</div>

<div class='info'>

<div class='box'>
📱
<h3>Mobile Banking</h3>
<p>
Transfer money instantly.
Manage debit cards.
Recharge & bill payments.
</p>
</div>

<div class='box'>
🌐
<h3>Internet Banking</h3>
<p>
View statements.
Download reports.
Manage beneficiaries.
</p>
</div>

<div class='box'>
☎️
<h3>24×7 Support</h3>
<p>
Phone: +91 9494207062
<br><br>
Email: narsingbeesetti22@gmail.com
</p>
</div>

</div>

<div class='footer'>
<b>Thank you for banking with Real Bank.</b>
<br><br>
© 2026 Real Bank
<br>
This is an automated email. Please do not reply.
</div>

</div>

</div>

</body>

</html>"]

