}

.container{
    max-width:650px;
    margin:40px auto;
    background:#ffffff;
    border-radius:12px;
    overflow:hidden;
    box-shadow:0 8px 25px rgba(0,0,0,.12);
}

.header{
    background:linear-gradient(90deg,#0047AB,#0066ff);
    color:white;
    padding:30px;
    text-align:center;
}

.logo{
    font-size:28px;
    font-weight:bold;
}

.subtitle{
    margin-top:8px;
    font-size:14px;
    opacity:.9;
}

.success{
    text-align:center;
    padding:30px 20px;
}

.success-icon{
    width:80px;
    height:80px;
    line-height:80px;
    margin:auto;
    border-radius:50%;
    background:#16a34a;
    color:white;
    font-size:40px;
}

.success h2{
    color:#16a34a;
    margin-top:20px;
}

.message{
    color:#555;
    font-size:15px;
}

.card{
    margin:25px;
    border-radius:10px;
    border:1px solid #e5e7eb;
    overflow:hidden;
}

.card-header{
    background:#f8fafc;
    padding:15px;
    font-size:18px;
    font-weight:bold;
    color:#1f2937;
}

table{
    width:100%;
    border-collapse:collapse;
}

td{
    padding:14px;
    border-bottom:1px solid #ececec;
}

.label{
    color:#666;
    font-weight:bold;
}

.value{
    text-align:right;
    color:#111827;
}

.amount{
    color:#16a34a;
    font-size:22px;
    font-weight:bold;
}

.footer{
    background:#f8fafc;
    padding:25px;
    text-align:center;
    color:#777;
    font-size:13px;
}

.note{
    margin:20px;
    background:#eef7ff;
    border-left:5px solid #0ea5e9;
    padding:15px;
    color:#444;
    border-radius:5px;
}
</style>

</head>

<body>

<div class='container'>

<div class='header'>
