</p>

</div>

<div class='card'>

<div class='card-header'>
Transaction Summary
</div>

<table>

<tr>
<td class='label'>Transaction ID</td>
<td class='value'>" ++ (vars.transactionId default "N/A") ++ "</td>
</tr>

<tr>
<td class='label'>Account Number</td>
<td class='value'>" ++ (vars.accountNumber as String) ++ "</td>
</tr>

<tr>
<td class='label'>Transaction Type</td>
<td class='value'>DEPOSITED</td>
</tr>

<tr>
<td class='label'>Amount Credited</td>
<td class='value amount'>₹" ++ ((vars.amount default 0) as String) ++ "</td>
</tr>

<tr>
<td class='label'>Available Balance</td>
<td class='value'>₹" ++ ((account.BALANCE default 0) as String) ++ "</td>
</tr>

<tr>
<td class='label'>Transaction Date</td>
<td class='value'>" ++ ((now()) as String {format:'dd MMM yyyy hh:mm a'}) ++ "</td>
</tr>

<tr>
