</div>

</div>

</body>
</html>"]

snowflake:update.snowflake:sql:
UPDATE MYDATABASE.PUBLIC.BANK_CUSTOMER_DATA SET BALANCE = COALESCE(BALANCE, 0) + :amount,
TRANSACTIONS = ARRAY_APPEND( COALESCE(TRANSACTIONS, ARRAY_CONSTRUCT()), OBJECT_CONSTRUCT( 'accountNumber', ACCOUNTNUMBER, 'transactionType', 'DEPOSIT', 'amount', :amount, 'balanceAfterTransaction', COALESCE(BALANCE, 0) + :amount, 'timestamp', CURRENT_TIMESTAMP() ) )
WHERE ACCOUNTNUMBER = :accountNumber;

