snowflake:select.snowflake:sql:
SELECT c.FULLNAME, c.MOBILENUMBER, c.ACCOUNTNUMBER, c.EMAIL, c.STATUS, c.BALANCE, c.ADDRESS, c.ADHARNUMBER, c.BANKNAME, c.CREATED_AT,
t.value['transactionType']::STRING AS TRANSACTIONTYPE, t.value['amount']::NUMBER AS AMOUNT, t.value['balanceAfterTransaction']::NUMBER AS BALANCEAFTERTRANSACTION, t.value['timestamp']::STRING AS TIMESTAMP
FROM BANK_CUSTOMER_DATA c, LATERAL FLATTEN(input => c.TRANSACTIONS) t WHERE c.MOBILENUMBER = :MOBILENUMBER;

